<?php
 namespace WPAICG\ContentWriter\Ajax\Actions\StandardGeneration; use WPAICG\ContentWriter\Ajax\Actions\AIPKit_Content_Writer_Standard_Generation_Action; use WP_Error; if (!defined('ABSPATH')) { exit; } function handle_error_response_logic(AIPKit_Content_Writer_Standard_Generation_Action $handler, WP_Error $error, array $validated_params, string $conversation_uuid): void { if ($handler->log_storage) { $error_data = $error->get_error_data() ?? []; $request_payload_log_on_error = is_array($error_data) ? ($error_data['request_payload_log'] ?? null) : null; $handler->log_storage->log_message(array_merge($handler->build_content_writer_log_base( $conversation_uuid, (string) ($validated_params['provider'] ?? ''), (string) ($validated_params['model'] ?? '') ), [ 'message_role' => 'bot', 'message_content' => "Error generating content (AJAX): " . $error->get_error_message(), 'request_payload' => $request_payload_log_on_error, ])); } $handler->send_wp_error($error); } 